/**
 * iframe embed entry.
 *
 * Builds to dist/iframe.min.js and auto-bootstraps using query params:
 * - projectId (required)
 * - backend_url / backendUrl (optional)
 *
 * Example:
 *   /embed.html?projectId=...&backend_url=http://46.225.89.136/api
 */

import './styles/viewer.css';
import { Viewer } from './core/ViewerPsv.js';
import { parseQueryParams, isValidUuid } from './core/Utils.js';
import { ensureViewerStyles } from './core/ensureViewerStyles.js';

function escapeHtml(s) {
  return String(s)
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#039;');
}

function renderError(root, title, message, details = null) {
  root.classList.add('p360-root');
  root.innerHTML = '';
  const wrap = document.createElement('div');
  wrap.className = 'p360-error';
  const detailsHtml = details
    ? `<details style="margin-top:12px">
         <summary style="cursor:pointer;color:rgba(231,234,243,0.95);font-size:13px">Details</summary>
         <pre style="white-space:pre-wrap;word-break:break-word;margin:10px 0 0;color:rgba(154,164,178,1);font-size:12px;line-height:1.45">${escapeHtml(details)}</pre>
       </details>`
    : '';

  wrap.innerHTML = `
    <div class="p360-error-card">
      <h1>${escapeHtml(title)}</h1>
      <p>${escapeHtml(message)}</p>
      ${detailsHtml}
    </div>
  `;
  root.appendChild(wrap);
}

async function boot() {
  ensureViewerStyles();
  const root = document.getElementById('panorama360-root') || document.body;
  const q = parseQueryParams();

  const projectId = q.projectId;
  const backendUrlRaw =
    q.backend_url ||
    q.backendUrl ||
    q.apiBaseUrl || // backwards compat
    import.meta.env.VITE_BACKEND_URL ||
    import.meta.env.VITE_API_BASE_URL ||
    'http://46.225.89.136/api';
  const backendUrl = (backendUrlRaw || '').toString().trim();
  const backendUrlSource =
    (q.backend_url || q.backendUrl || q.apiBaseUrl) ? 'query' :
    (import.meta.env.VITE_BACKEND_URL || import.meta.env.VITE_API_BASE_URL) ? 'env' :
    'default';

  if (!projectId || !isValidUuid(projectId)) {
    renderError(root, 'Missing projectId', 'Provide `?projectId=UUID` to load a Panorama360 project.');
    return;
  }

  const viewer = new Viewer({
    container: root,
    projectId,
    backendUrl
  });

  try {
    await viewer.init();
    // Expose minimal API for iframe-hosted integrations if needed.
    window.Panorama360 = {
      init: async () => viewer,
      loadPanorama: async (id) => viewer.loadPanorama(id, { reason: 'api' }),
      enterVR: async () => viewer.enterVR(),
      exitVR: async () => viewer.exitVR(),
      toggleFloorplan: () => viewer.toggleFloorplan(),
      destroy: async () => viewer.destroy()
    };
  } catch (err) {
    const basic = err?.message || String(err);
    const meta = {
      projectId,
      backendUrl,
      backendUrlSource,
      note: 'If this is "TypeError: Failed to fetch", common causes are: backend down, blocked by CORS, network/DNS, browser extensions, or mixed-content.',
      hints: [
        'Verify the backend is running and reachable.',
        'If running the widget on a different origin/port, enable CORS on the backend.',
        'You can pass `backend_url` via query param or set VITE_BACKEND_URL and restart Vite.'
      ]
    };
    const details =
      `Error:\n${basic}\n\n` +
      `Resolved config:\n${JSON.stringify(meta, null, 2)}\n\n` +
      `Stack:\n${err?.stack || '(no stack)'}`;

    renderError(root, 'Failed to load project', basic, details);
  }
}

boot();


