/**
 * Viewer (PSV implementation)
 *
 * Uses Photo Sphere Viewer v4 + MarkersPlugin (same stack as your editor),
 * so camera feel + hotspot yaw/pitch coordinates match exactly.
 */

import { Floorplan } from './Floorplan.js';
import { Analytics } from './Analytics.js';
import { ApiService } from './ApiService.js';
import { resolveContainer } from './Utils.js';
import { ensurePsvAssets } from './ensurePsvAssets.js';

export class Viewer {
  constructor(options) {
    this.options = { enableVR: false, ...options };
    this.container = resolveContainer(this.options.container);
    this.container.classList.add('p360-root');

    this._destroyed = false;
    this._debug =
      !!this.options.debug ||
      (typeof window !== 'undefined' && !!window.__P360_DEBUG);

    const backendUrl =
      this.options.backendUrl ||
      this.options.backend_url ||
      this.options.apiBaseUrl ||
      'http://46.225.89.136/api';
    this.api = new ApiService({ baseUrl: backendUrl });
    this.analytics = new Analytics({ projectId: this.options.projectId });

    this._project = null;
    this._tourData = null;

    // Interior state
    this._interiors = [];
    this._interior = null;
    this._hudInteriorButtons = new Map();

    // Floor state (house type projects)
    this._floors = []; // array of floor numbers
    this._currentFloor = null; // currently selected floor number

    // Panoramas + floorplan
    this._panoramas = [];
    this._floorplans = [];
    this._currentPanoramaId = null;
    this._currentFloorplanId = null;
    this._autorotating = false;

    // View mode (360 via PSV, 2d/3d via overlay images)
    this._viewMode = '360'; // '360' | '2d' | '3d'

    // Overlay state
    this._overlay = this._createOverlay();
    this._overlayMode = 'none';
    this._overlayUrls = [];
    this._overlayIndex = 0;
    this._topViewUrl = null;
    this._middleCutUrls = [];

    // PSV mount point (below HUD)
    this._psvEl = document.createElement('div');
    this._psvEl.className = 'p360-psv';
    Object.assign(this._psvEl.style, {
      position: 'absolute',
      inset: '0',
      zIndex: '1'
    });
    this.container.appendChild(this._psvEl);

    // HUD + floorplan overlay (your existing layout/CSS)
    this._hud = this._createHud();
    this.floorplan = new Floorplan({
      root: this.container,
      onNavigatePanorama: (id) => this._onFloorplanNavigate(id),
      onRoomClick: (room) => this._onFloorplanRoomClick(room),
      onRoomHover: (room) => this._onFloorplanRoomHover(room),
      onFloorSelect: (floor) => this._setFloor(floor)
    });

    // PSV runtime
    this._PSV = null;
    this._psv = null;
    this._markers = null;
    this._gyro = null;
    this._stereo = null;

    // Bindings
    this._onPageHide = () => {
      if (this._destroyed) return;
      this.analytics.track('session_end', { panoramaId: this._currentPanoramaId, reason: 'pagehide' });
    };
    window.addEventListener('pagehide', this._onPageHide);
  }

  _dlog(...args) {
    if (!this._debug) return;
    // eslint-disable-next-line no-console
    console.debug('[Panorama360]', ...args);
  }

  async init() {
    await this.analytics.track('session_start', { userAgent: navigator.userAgent });
    this._PSV = await ensurePsvAssets();
    await this._loadProjectData();

    const startId =
      this._project?.settings?.start_panorama_id ||
      this._panoramas?.[0]?.id ||
      null;
    if (!startId) throw new Error('Panorama360: project has no panoramas');

    // Create PSV viewer (navbar disabled; we render our own HUD)
    const startPano = this._getPanoramaById(startId);
    if (!startPano?.image_url) throw new Error('Panorama360: start panorama has no image_url');

    const PSV = this._PSV;
    const plugins = [
      // Markers plugin for hotspots
      [PSV.MarkersPlugin, { markers: [] }]
    ];

    // Optional: gyroscope + stereo "VR mode" (mobile)
    if (PSV.GyroscopePlugin) plugins.unshift(PSV.GyroscopePlugin);
    if (PSV.StereoPlugin) plugins.unshift(PSV.StereoPlugin);

    this._psv = new PSV.Viewer({
      container: this._psvEl,
      panorama: startPano.image_url,
      navbar: false,
      touchmoveTwoFingers: true,
      mousewheelCtrlKey: false,
      maxFov: 102,
      defaultZoomLvl: 0,
      plugins
    });

    this._markers = this._psv.getPlugin?.(PSV.MarkersPlugin) || null;
    this._gyro = this._psv.getPlugin?.('gyroscope') || this._psv.getPlugin?.(PSV.GyroscopePlugin) || null;
    this._stereo = this._psv.getPlugin?.('stereo') || this._psv.getPlugin?.(PSV.StereoPlugin) || null;

    if (this._markers?.on) {
      this._markers.on('select-marker', (...args) => {
        // PSV v4 uevent: callback receives (marker) or (marker, doubleClick).
        const marker = args.find(a => a && typeof a === 'object' && a.id) || null;
        if (!marker) return;
        const data = marker.data || marker.config?.data || null;
        this._dlog('hotspot clicked', marker.id, data);
        if (data?.target_panorama_id) {
          this.loadPanorama(data.target_panorama_id, { reason: 'hotspot' }).catch((e) => {
            // eslint-disable-next-line no-console
            console.warn('[Panorama360] hotspot navigate failed', data.target_panorama_id, e);
          });
        }
      });
    }

    this._psv.on?.('autorotate', () => {
      const on = this._psv.isAutorotateEnabled?.() ?? this._psv.prop?.autorotateEnabled ?? false;
      this._autorotating = on;
      this._btnAutorotate?.classList.toggle('is-active', on);
    });

    const onFsChange = () => {
      const isFs = document.fullscreenElement === this.container || document.webkitFullscreenElement === this.container;
      this.container.classList.toggle('is-fullscreen', isFs);
    };
    document.addEventListener('fullscreenchange', onFsChange);
    document.addEventListener('webkitfullscreenchange', onFsChange);

    await new Promise((resolve) => {
      if (this._psv.isReady?.()) return resolve();
      this._psv.once?.('ready', resolve);
      setTimeout(resolve, 8000);
    });

    if (this._btnZoom) this._btnZoom.textContent = '1×';

    // The constructor already loaded the start panorama image.
    // Set hotspots + floorplan directly (no redundant setPanorama).
    this._currentPanoramaId = startId;
    const initHotspots = await this._getHotspotsByPanorama(startId);
    this._setHotspotsPsv(initHotspots);

    const startPanoFp = this._getPanoramaById(startId);
    const fp = startPanoFp?.floorplan_id
      ? this._getFloorplanById(startPanoFp.floorplan_id)
      : (this._floorplans[0] || null);
    await this.floorplan.setData(fp, this._panoramas);
    this.floorplan.setRoomMeta(this._getRoomMetaMapFromProject());
    const initPathKey = this._getCurrentPanoramaPathKey();
    this.floorplan.setActiveRoom(initPathKey || startPanoFp?.room_id || this._getRoomIdForPanorama(startPanoFp) || null);
    this._buildFloorSelectorState?.();

    await this.analytics.track('panorama_loaded', { panoramaId: startId, reason: 'initial', viewMode: '360' });
    this._updateHudState?.();
  }

  getViewYawPitch() {
    if (!this._psv?.getPosition) return { yaw: 0, pitch: 0 };
    const pos = this._psv.getPosition(); // radians
    const radToDeg = (r) => (r * 180) / Math.PI;
    const normYaw = (deg) => ((deg + 180) % 360 + 360) % 360 - 180;
    return { yaw: normYaw(radToDeg(pos.longitude)), pitch: radToDeg(pos.latitude) };
  }

  async enterVR() {
    // PSV v4 uses StereoPlugin as "VR-like" cardboard mode (requires gyroscope).
    if (!this._stereo?.start) throw new Error('Panorama360: VR mode is not available (Stereo plugin missing)');
    await this._stereo.start();
  }

  async exitVR() {
    if (!this._stereo?.stop) return;
    this._stereo.stop();
  }

  toggleFloorplan() {
    return this.floorplan?.toggle?.() || this.floorplan?.setVisible?.(!this.floorplan?.isVisible?.());
  }

  async loadPanorama(panoramaId, { reason = 'api' } = {}) {
    if (this._destroyed) return;
    const pano = this._getPanoramaById(panoramaId);
    if (!pano) throw new Error(`Panorama360: panorama not found: ${panoramaId}`);

    this._currentPanoramaId = pano.id;
    this._currentFloorplanId = pano.floorplan_id || null;

    // 2D/3D overlay modes
    if (this._viewMode !== '360') {
      this._applyOverlayMode(this._viewMode);
      return;
    }

    this._overlay.setVisible(false);
    this._psvEl.style.display = '';

    const isInteriorSwitch = reason === 'interior';
    const isFloorSwitch = reason === 'floor';
    const isSlowTransition = isInteriorSwitch || isFloorSwitch;
    if (isSlowTransition) this.container.classList.add('is-transitioning');

    try {
      // Keep current position when switching interiors/panos (like editor)
      const keepPos = this._psv?.getPosition ? this._psv.getPosition() : null;

      // Load panorama in PSV
      if (this._psv?.setPanorama) {
        await this._psv.setPanorama(pano.image_url, {
          transition: 'fade',
          speed: isSlowTransition ? '2rpm' : '5rpm',
          longitude: keepPos?.longitude,
          latitude: keepPos?.latitude
        });
      }

      // Let PSV finish internal state updates before placing markers
      await new Promise(r => setTimeout(r, isSlowTransition ? 170 : 120));
      const hotspotRows = await this._getHotspotsByPanorama(pano.id);
      this._dlog('loadPanorama hotspots for', pano.id, '→', hotspotRows.length, 'hotspot(s)');
      this._setHotspotsPsv(hotspotRows);

      // Floorplan data
      const fp =
        pano.floorplan_id
          ? this._getFloorplanById(pano.floorplan_id)
          : (this._floorplans[0] || null);
      await this.floorplan.setData(fp, this._panoramas);
      this.floorplan.setRoomMeta(this._getRoomMetaMapFromProject());
      // Prefer path key (e.g. "path-0") for SVG room highlighting so it matches
      // data-room attributes in the SVG. Fall back to room_id for legacy SVGs.
      const pathKey = this._getCurrentPanoramaPathKey();
      this.floorplan.setActiveRoom(pathKey || pano.room_id || this._getRoomIdForPanorama(pano) || null);

      await this.analytics.track('panorama_loaded', { panoramaId: pano.id, reason, viewMode: this._viewMode });
      this._updateHudState?.();
    } finally {
      if (isSlowTransition) {
        setTimeout(() => this.container.classList.remove('is-transitioning'), 140);
      }
    }
  }

  async destroy() {
    if (this._destroyed) return;
    this._destroyed = true;
    window.removeEventListener('pagehide', this._onPageHide);
    if (this._hudOnDocClickFloor) document.removeEventListener('click', this._hudOnDocClickFloor);
    try { await this.analytics.track('session_end', { panoramaId: this._currentPanoramaId }); } catch {}
    try { this._markers?.destroy?.(); } catch {}
    try { this._psv?.destroy?.(); } catch {}
    this.floorplan?.destroy?.();
    if (this._hud?.parentNode) this._hud.parentNode.removeChild(this._hud);
    if (this._psvEl?.parentNode) this._psvEl.parentNode.removeChild(this._psvEl);
  }

  // -----------------------------
  // Data mapping helpers (copied/adapted from previous Viewer)
  // -----------------------------

  async _loadProjectData() {
    const projectId = this.options.projectId;
    const payload = await this.api.getProject(projectId);
    // Support APIs that wrap project object, but prefer the candidate that actually has project fields.
    const candidates = [
      payload,
      payload?.project,
      payload?.data?.project,
      payload?.data
    ];
    this._project =
      candidates.find((c) => c && typeof c === 'object' && (c.images || c.tour_data || c.id)) ||
      payload;
    this._tourData = this._project?.tour_data || null;

    this._floors = this._getFloorsFromTourData(this._tourData);
    this._currentFloor = this._floors.length > 0 ? this._floors[0] : null;

    this._interiors = this._getInteriorNamesFromProject(this._project);
    this._interior = this._pickDefaultInterior(this._interiors, this._project, payload);
    // eslint-disable-next-line no-console
    console.info('[Panorama360] default interior resolved', {
      defaultTheme: this._extractDefaultTheme(this._project, payload),
      interiors: this._interiors,
      selected: this._interior
    });
    this._panoramas = this._buildPanoramasForInterior(this._interior);
    this._floorplans = this._buildFloorplansFromProject(this._project);

    this._topViewUrl = this._inferTopViewUrl();
    this._middleCutUrls = await this._inferMiddleCutUrls();
    this._buildInteriorButtons?.();
    this._buildFloorSelectorState?.();
    this._updateHudState?.();
  }

  _getInteriorNamesFromProject(project) {
    // House type: panoramas are in images.floors[floor].interiors['360'][interior]
    if (this._isHouseProject(project)) {
      const floors = project?.images?.floors || {};
      const allInteriors = new Set();
      for (const floorData of Object.values(floors)) {
        const imgs360 = floorData?.interiors?.['360'] || null;
        if (imgs360 && typeof imgs360 === 'object' && !Array.isArray(imgs360)) {
          for (const [k, v] of Object.entries(imgs360)) {
            if (Array.isArray(v) && v.length > 0) allInteriors.add(k);
          }
        }
      }
      return [...allInteriors];
    }
    const images360 = project?.images?.['360'] || null;
    if (images360 && typeof images360 === 'object' && !Array.isArray(images360)) {
      return Object.keys(images360)
        .filter((k) => Array.isArray(images360?.[k]) && images360[k].length > 0)
        // Preserve backend JSON key order (matches your API response / editor expectation).
        // If you want alphabetical, sort at the backend instead.
        ;
    }
    return [];
  }

  _isHouseProject(project) {
    // A project is "house" type if tour_data is an array with items having a numeric floor field
    const td = project?.tour_data || this._tourData;
    if (Array.isArray(td) && td.length > 0) {
      return td.some((item) => typeof item?.floor === 'number');
    }
    // Also check if images has a "floors" key (house-style images structure)
    if (project?.images?.floors && typeof project.images.floors === 'object') {
      return true;
    }
    return false;
  }

  _getFloorsFromTourData(tourData) {
    // Primary: numeric floor fields in tour_data array
    if (Array.isArray(tourData) && tourData.length > 0) {
      const fromTd = tourData
        .map((item) => item?.floor)
        .filter((f) => typeof f === 'number' && f !== null);
      if (fromTd.length > 0) {
        return [...new Set(fromTd)].sort((a, b) => a - b);
      }
    }
    // Fallback: numeric keys in images.floors
    const floorsObj = this._project?.images?.floors;
    if (floorsObj && typeof floorsObj === 'object') {
      const nums = Object.keys(floorsObj)
        .map((k) => Number(k))
        .filter((n) => !isNaN(n));
      if (nums.length > 0) return [...new Set(nums)].sort((a, b) => a - b);
    }
    return [];
  }

  async _setFloor(floorNum) {
    if (floorNum === this._currentFloor) return;
    // Capture path index before switching floor (paths may differ per floor).
    const pathIdx = this._getCurrentPanoramaPathIndex();
    this._currentFloor = floorNum;
    this._panoramas = this._buildPanoramasForInterior(this._interior);
    this._floorplans = this._buildFloorplansFromProject(this._project);
    this._topViewUrl = this._inferTopViewUrl();
    this._middleCutUrls = await this._inferMiddleCutUrls();
    this._buildFloorSelectorState?.();
    this._updateHudState?.();
    // Try to land on same path index in the new floor, else first panorama.
    const byIndex = pathIdx >= 0 ? this._getPanoramaByPathIndex(pathIdx) : null;
    const target = byIndex || this._panoramas[0] || null;
    if (target?.id) await this.loadPanorama(target.id, { reason: 'floor' });
  }

  _normalizeInteriorName(value) {
    return String(value || '')
      .trim()
      .toLowerCase()
      .replace(/[_\-\s]+/g, '')
      .replace(/[^a-z0-9]/g, '');
  }

  _readThemeFromObjectLoose(obj = null) {
    if (!obj || typeof obj !== 'object') return '';
    const wantedKeys = new Set(['defaulttheme', 'defaulththeme', 'defaultinterior']);
    for (const [key, value] of Object.entries(obj)) {
      const nk = this._normalizeInteriorName(key);
      if (!wantedKeys.has(nk)) continue;
      const v = String(value || '').trim();
      if (v) return v;
    }
    return '';
  }

  _extractDefaultTheme(project = null, payload = null) {
    // eslint-disable-next-line no-console
    console.info('[Panorama360] _extractDefaultTheme raw', { default_theme: project?.default_theme, projectKeys: project ? Object.keys(project) : null });
    const candidates = [
      project?.default_theme,
      project?.defaulth_theme,
      project?.defaultTheme,
      project?.default_interior,
      project?.defaultInterior,
      project?.settings?.default_theme,
      project?.settings?.defaulth_theme,
      project?.settings?.defaultTheme,
      project?.settings?.default_interior,
      project?.settings?.defaultInterior,
      payload?.default_theme,
      payload?.defaulth_theme,
      payload?.defaultTheme,
      payload?.data?.default_theme,
      payload?.data?.defaulth_theme,
      payload?.data?.defaultTheme,
      payload?.project?.default_theme,
      payload?.project?.defaulth_theme,
      payload?.project?.defaultTheme,
      payload?.data?.project?.default_theme,
      payload?.data?.project?.defaulth_theme,
      payload?.data?.project?.defaultTheme,
      this._readThemeFromObjectLoose(project),
      this._readThemeFromObjectLoose(project?.settings),
      this._readThemeFromObjectLoose(payload),
      this._readThemeFromObjectLoose(payload?.settings),
      this._readThemeFromObjectLoose(payload?.data),
      this._readThemeFromObjectLoose(payload?.data?.settings),
      this._readThemeFromObjectLoose(payload?.project),
      this._readThemeFromObjectLoose(payload?.project?.settings),
      this._readThemeFromObjectLoose(payload?.data?.project),
      this._readThemeFromObjectLoose(payload?.data?.project?.settings)
    ];
    for (const value of candidates) {
      const v = String(value || '').trim();
      if (v) return v;
    }
    return '';
  }

  _pickDefaultInterior(interiors, project = null, payload = null) {
    if (!Array.isArray(interiors) || !interiors.length) return null;
    const wanted = this._extractDefaultTheme(project, payload);
    if (!wanted) return interiors[0];

    const wantedNorm = this._normalizeInteriorName(wanted);
    const exact = interiors.find((name) => this._normalizeInteriorName(name) === wantedNorm);
    if (exact) return exact;

    // Fallback: choose best normalized similarity (handles Elegancy vs Elegance).
    let best = null;
    let bestScore = -1;
    for (const name of interiors) {
      const n = this._normalizeInteriorName(name);
      if (!n) continue;
      let prefix = 0;
      const maxPrefix = Math.min(n.length, wantedNorm.length);
      while (prefix < maxPrefix && n[prefix] === wantedNorm[prefix]) prefix += 1;
      const prefixScore = prefix / Math.max(n.length, wantedNorm.length, 1);
      const includesScore = (n.includes(wantedNorm) || wantedNorm.includes(n)) ? 1 : 0;
      const score = Math.max(prefixScore, includesScore);
      if (score > bestScore) {
        bestScore = score;
        best = name;
      }
    }
    // Require reasonable similarity, otherwise keep deterministic first interior.
    return bestScore >= 0.55 ? best : interiors[0];
  }

  _getAssetUrl(asset) {
    if (!asset) return null;
    if (typeof asset === 'string') return asset.trim() || null;
    if (typeof asset?.publicUrl === 'string' && asset.publicUrl.trim()) return asset.publicUrl.trim();
    if (typeof asset?.url === 'string' && asset.url.trim()) return asset.url.trim();
    return null;
  }

  _getAssetName(asset) {
    if (!asset) return null;
    if (typeof asset?.fileName === 'string' && asset.fileName.trim()) return asset.fileName.trim();
    if (typeof asset?.name === 'string' && asset.name.trim()) return asset.name.trim();
    if (typeof asset?.path === 'string' && asset.path.trim()) return asset.path.trim().split('/').pop() || asset.path.trim();
    return null;
  }

  _getProjectImages(kind, interior = null) {
    // House type: get images from floors structure
    if (this._isHouseProject(this._project) && this._currentFloor !== null && (kind === '2d' || kind === '3d')) {
      const floorKey = String(this._currentFloor);
      const floorData = this._project?.images?.floors?.[floorKey];
      const interiorImgs = floorData?.interiors?.[kind] ?? null;
      if (interiorImgs && typeof interiorImgs === 'object') {
        if (interior && Array.isArray(interiorImgs?.[interior])) return interiorImgs[interior];
        const firstKey = Object.keys(interiorImgs).find((k) => Array.isArray(interiorImgs?.[k]) && interiorImgs[k].length) || null;
        if (firstKey) return interiorImgs[firstKey];
      }
      // Fallback: check images.other for 3d assets shared across floors
      const otherImgs = this._project?.images?.other?.interiors?.[kind] ?? null;
      if (otherImgs && typeof otherImgs === 'object') {
        if (interior && Array.isArray(otherImgs?.[interior])) return otherImgs[interior];
        const firstKey = Object.keys(otherImgs).find((k) => Array.isArray(otherImgs?.[k]) && otherImgs[k].length) || null;
        if (firstKey) return otherImgs[firstKey];
      }
      return [];
    }
    const imgs = this._project?.images?.[kind] ?? null;
    if (!imgs) return [];
    if (Array.isArray(imgs)) return imgs;
    if (imgs && typeof imgs === 'object') {
      if (interior && Array.isArray(imgs?.[interior])) return imgs[interior];
      const firstKey = Object.keys(imgs).find((k) => Array.isArray(imgs?.[k]) && imgs[k].length) || null;
      if (firstKey) return imgs[firstKey];
    }
    return [];
  }

  _buildPanoramasForInterior(interior) {
    const projectId = this.options.projectId;

    // House type: get panoramas from images.floors[currentFloor].interiors['360'][interior]
    if (this._isHouseProject(this._project) && this._currentFloor !== null) {
      const floorKey = String(this._currentFloor);
      const floorData = this._project?.images?.floors?.[floorKey];
      const list = floorData?.interiors?.['360']?.[interior] || [];
      const isRaster = (name) => /\.(webp|jpe?g|png)$/i.test(String(name || '').split('?')[0]);
      if (Array.isArray(list) && list.length) {
        return list
          .map((asset) => {
            const url = this._getAssetUrl(asset);
            const fileName = this._getAssetName(asset);
            if (!url || !fileName || !isRaster(fileName)) return null;
            return {
              id: fileName,
              project_id: projectId,
              name: fileName,
              image_url: url,
              room_id: null,
              floorplan_id: null,
              floorplan_x: null,
              floorplan_y: null
            };
          })
          .filter(Boolean)
          .sort((a, b) => String(a.id).localeCompare(String(b.id)));
      }
      return [];
    }

    const list = this._getProjectImages('360', interior);
    const isRaster = (name) => /\.(webp|jpe?g|png)$/i.test(String(name || '').split('?')[0]);

    const roomMap = this._project?.floorplan_data?.room_map && typeof this._project.floorplan_data.room_map === 'object'
      ? this._project.floorplan_data.room_map
      : null;
    const panoIdToRoomId = new Map();
    if (roomMap) {
      for (const [roomId, ref] of Object.entries(roomMap)) {
        if (!ref) continue;
        const file = String(ref).split('/').pop() || String(ref);
        panoIdToRoomId.set(file, roomId);
      }
    }

    if (Array.isArray(list) && list.length) {
      return list
        .map((asset) => {
          const url = this._getAssetUrl(asset);
          const fileName = this._getAssetName(asset);
          if (!url || !fileName || !isRaster(fileName)) return null;
          return {
            id: fileName,
            project_id: projectId,
            name: fileName,
            image_url: url,
            room_id: panoIdToRoomId.get(fileName) || null,
            floorplan_id: null,
            floorplan_x: null,
            floorplan_y: null
          };
        })
        .filter(Boolean)
        .slice()
        .sort((a, b) => String(a.id).localeCompare(String(b.id)));
    }

    // Fallback: derive from tour_data.scenes
    const scenes = this._tourData?.scenes && typeof this._tourData.scenes === 'object' ? this._tourData.scenes : {};
    return Object.values(scenes).map((scene) => ({
      id: scene.id,
      project_id: projectId,
      name: scene.name || null,
      image_url: scene.image || null,
      room_id: scene.roomId || scene.room_id || null,
      floorplan_id: null,
      floorplan_x: null,
      floorplan_y: null
    }));
  }

  _buildFloorplansFromProject(project) {
    // House type: read floorplan assets from images.floors[floor].floorplan
    if (this._isHouseProject(project) && this._currentFloor !== null) {
      const floorKey = String(this._currentFloor);
      const floorAssets = project?.images?.floors?.[floorKey]?.floorplan || [];
      const pickFromAssets = (extRe) => {
        for (const a of floorAssets) {
          const name = this._getAssetName(a) || '';
          const url = this._getAssetUrl(a);
          if (url && extRe.test(name.split('?')[0] || name)) return url;
        }
        return null;
      };
      const imageUrl = pickFromAssets(/\.(png|jpe?g|webp)$/i) || null;
      const svgUrl = pickFromAssets(/\.svg$/i) || null;
      if (imageUrl || svgUrl) {
        return [{
          id: `floorplan:floor:${this._currentFloor}`,
          project_id: this.options.projectId,
          image_url: imageUrl,
          svg_url: svgUrl,
          width: 1,
          height: 1
        }];
      }
      return [];
    }

    const fp = project?.floorplan_data && typeof project.floorplan_data === 'object' ? project.floorplan_data : null;
    const floorplanAssets = project?.images?.floorplan;
    const assets = Array.isArray(floorplanAssets) ? floorplanAssets : [];
    const pickFromAssets = (extRe) => {
      for (const a of assets) {
        const name = this._getAssetName(a) || '';
        const url = this._getAssetUrl(a);
        if (url && extRe.test(name.split('?')[0] || name)) return url;
      }
      return null;
    };
    const imageUrl =
      (typeof fp?.image_url === 'string' && fp.image_url.trim() ? fp.image_url.trim() : null) ||
      pickFromAssets(/\.(png|jpe?g|webp)$/i) ||
      null;
    const svgUrl =
      (typeof fp?.svg_url === 'string' && fp.svg_url.trim() ? fp.svg_url.trim() : null) ||
      pickFromAssets(/\.svg$/i) ||
      null;
    if (!imageUrl) return [];
    return [{
      id: fp?.id || 'floorplan:0',
      project_id: this.options.projectId,
      image_url: imageUrl,
      svg_url: svgUrl,
      width: fp?.width || 1,
      height: fp?.height || 1
    }];
  }

  _getFloorplanById(id) {
    return this._floorplans.find((f) => f.id === id) || null;
  }

  _getPanoramaById(idOrRef) {
    if (!idOrRef) return null;
    const raw = String(idOrRef);
    const rawNoQuery = raw.split('?')[0];
    const ref = raw.toLowerCase();
    const refNoQuery = rawNoQuery.toLowerCase();
    const refFileNoQuery = (rawNoQuery.split('/').pop() || rawNoQuery).toLowerCase();
    return (
      this._panoramas.find((p) => String(p.id).toLowerCase() === ref) ||
      this._panoramas.find((p) => p.name && String(p.name).toLowerCase() === ref) ||
      this._panoramas.find((p) => {
        const u = (p.image_url || '').toString();
        const uNoQuery = u.split('?')[0];
        return u.toLowerCase() === ref || uNoQuery.toLowerCase() === refNoQuery;
      }) ||
      this._panoramas.find((p) => {
        const url = p.image_url || '';
        const filename = (url.split('/').pop() || '').toLowerCase();
        const filenameNoQuery = filename.split('?')[0];
        return (
          filename === ref ||
          filenameNoQuery === refNoQuery ||
          filenameNoQuery === refFileNoQuery
        );
      }) ||
      null
    );
  }

  _findScene(panoramaId) {
    const tour = this._tourData || this._project?.tour_data || null;
    const scenes = tour?.scenes && typeof tour.scenes === 'object' ? tour.scenes : {};

    // 1. Exact key lookup
    if (scenes[panoramaId]) return scenes[panoramaId];

    // 2. Match by .id property
    const byId = Object.values(scenes).find((s) => s?.id === panoramaId);
    if (byId) return byId;

    // 3. Filename-based fuzzy match (strip paths & query strings)
    const panoFile = String(panoramaId).split('/').pop()?.split('?')[0]?.toLowerCase() || '';
    if (panoFile) {
      for (const [key, val] of Object.entries(scenes)) {
        const keyFile = key.split('/').pop()?.split('?')[0]?.toLowerCase() || '';
        const idFile = String(val?.id || '').split('/').pop()?.split('?')[0]?.toLowerCase() || '';
        if (keyFile === panoFile || idFile === panoFile) return val;
      }
    }
    return null;
  }

  async _getHotspotsByPanorama(panoramaId) {
    const scene = this._findScene(panoramaId);
    const hs = Array.isArray(scene?.hotspots) ? scene.hotspots : [];
    const normYawDeg = (deg) => ((deg + 180) % 360 + 360) % 360 - 180;
    const clampPitchDeg = (deg) => Math.max(-90, Math.min(90, deg));

    // eslint-disable-next-line no-console
    if (!scene) console.warn(`[Panorama360] no scene found for "${panoramaId}" – 0 hotspots`);

    return hs.map((h, idx) => ({
      id: `${panoramaId}::${idx}`,
      panorama_id: panoramaId,
      type: h?.type || h?.style || 'navigate',
      yaw: normYawDeg(Number(h?.yaw ?? 0)),
      pitch: clampPitchDeg(Number(h?.pitch ?? 0)),
      target_panorama_id: h?.targetId || h?.target_panorama_id || null,
      camera: h?.camera && typeof h.camera === 'object' ? h.camera : null,
      label: h?.label || null,
      preview: h?.preview || null
    }));
  }

  _getHotspotHtml(type) {
    const t = String(type || 'navigate').toLowerCase();
    if (t === 'door') {
      return '<div class="p360-hotspot p360-hotspot-door"><svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 120 120"><path fill="currentColor" d="M75.009 0V5.292H95.703V110.882H88.053V12.944H75.009V120L24.298 110.882V95.962V9.137L75.009 0ZM65.68 64.113C67.385 64.113 68.767 62.314 68.767 60.096C68.767 57.878 67.385 56.079 65.68 56.079C63.975 56.079 62.593 57.878 62.593 60.096C62.593 62.314 63.975 64.113 65.68 64.113Z"/></svg></div>';
    }
    if (t === 'stairs') {
      return '<div class="p360-hotspot p360-hotspot-stairs"><svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 120 100"><path fill="currentColor" d="M114.783 8.333H88.696C85.816 8.333 83.478 10.196 83.478 12.5V29.167H78.261V8.333H83.478C86.358 8.333 88.696 6.471 88.696 4.167C88.696 1.863 86.358 0 83.478 0H73.043C73.012 0 72.981.012 72.949.012C72.527.021 72.125.125 71.718.212C71.468.267 71.196.271 70.962.354C70.727.433 70.534.591 70.314.704C69.96.883 69.589 1.041 69.297 1.283L69.219 1.329 1.392 59.663C-.565 61.35-.445 63.988 1.663 65.55C2.67 66.296 3.943 66.667 5.216 66.667C6.615 66.667 8.013 66.217 9.041 65.333L10.434 64.137V70.833C7.554 70.833 5.216 72.696 5.216 75V95.833C5.216 98.137 7.554 100 10.434 100H114.783C117.663 100 120 98.137 120 95.833V12.5C120 10.196 117.663 8.333 114.783 8.333ZM36.521 50C33.641 50 31.304 51.863 31.304 54.167V70.834H20.869V55.163L36.521 41.7V50ZM67.826 29.167H62.609C59.728 29.167 57.391 31.029 57.391 33.334V50H46.956V33.334L46.831 32.833 67.826 14.779V29.167Z"/></svg></div>';
    }
    return '<div class="p360-hotspot p360-hotspot-view"><svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 120 120"><path fill="currentColor" d="M75 60C75 68.27 68.27 75 60 75C51.73 75 45 68.27 45 60C45 51.73 51.73 45 60 45C68.27 45 75 51.73 75 60ZM120 57.755C120 57.755 98.74 100 60.075 100C24.175 100 0 57.755 0 57.755C0 57.755 22.23 20 60.075 20C98.545 20 120 57.755 120 57.755ZM85 60C85 46.215 73.785 35 60 35C46.215 35 35 46.215 35 60C35 73.785 46.215 85 60 85C73.785 85 85 73.785 85 60Z"/></svg></div>';
  }

  _setHotspotsPsv(rows) {
    if (!this._markers) {
      // eslint-disable-next-line no-console
      console.warn('[Panorama360] markers plugin not available – hotspots will not render');
      return;
    }
    try { this._markers.clearMarkers?.(); } catch (e) { this._dlog('clearMarkers error', e); }
    const count = (rows || []).length;
    for (const row of rows || []) {
      try {
        // PSV v4 MarkersPlugin requires longitude/latitude at the TOP level (not nested).
        this._markers.addMarker({
          id: row.id,
          longitude: `${row.yaw}deg`,
          latitude: `${row.pitch}deg`,
          html: this._getHotspotHtml(row.type),
          anchor: 'center center',
          tooltip: row.label || undefined,
          data: row
        });
      } catch (e) {
        // eslint-disable-next-line no-console
        console.warn('[Panorama360] addMarker failed', row.id, e);
      }
    }
    // eslint-disable-next-line no-console
    if (count) console.info(`[Panorama360] ${count} hotspot(s) placed`);
  }

  _getRoomMetaMapFromProject() {
    const fp = this._project?.floorplan_data;
    if (!fp || typeof fp !== 'object') return {};
    const out = {};
    if (Array.isArray(fp.rooms)) {
      for (const r of fp.rooms) {
        const roomId = String(r?.roomId || r?.id || '').trim();
        if (!roomId) continue;
        out[roomId] = { name: r?.name ?? null, status: r?.status ?? null, panoramaId: r?.panoramaId ?? null };
      }
    }
    const roomStatus = fp.room_status && typeof fp.room_status === 'object' ? fp.room_status : null;
    const roomNames = fp.room_names && typeof fp.room_names === 'object' ? fp.room_names : null;
    const roomMap = fp.room_map && typeof fp.room_map === 'object' ? fp.room_map : null;
    if (roomStatus) for (const [roomId, status] of Object.entries(roomStatus)) out[roomId] = { ...(out[roomId] || {}), status: status ?? null };
    if (roomNames) for (const [roomId, name] of Object.entries(roomNames)) out[roomId] = { ...(out[roomId] || {}), name: name ?? null };
    if (roomMap) for (const [roomId, panoramaId] of Object.entries(roomMap)) out[roomId] = { ...(out[roomId] || {}), panoramaId: panoramaId ?? null };
    return out;
  }

  _getRoomIdForPanorama(pano) {
    if (!pano) return null;
    const map = this._project?.floorplan_data?.room_map || null;
    if (!map || typeof map !== 'object') return null;
    const panoId = pano?.id ? String(pano.id) : '';
    const panoName = pano?.name ? String(pano.name) : '';
    const panoUrl = pano?.image_url ? String(pano.image_url) : '';
    const panoUrlNoQuery = panoUrl.split('?')[0];
    const panoFile = panoUrl ? panoUrl.split('/').pop() : '';
    const panoFileNoQuery = panoFile.split('?')[0];
    for (const [roomId, ref] of Object.entries(map)) {
      if (!ref) continue;
      const v = String(ref);
      const vNoQuery = v.split('?')[0];
      const vFile = v.split('/').pop() || v;
      const vFileNoQuery = vFile.split('?')[0];
      if (
        v === panoId ||
        v === panoName ||
        v === panoFile ||
        v === panoFileNoQuery ||
        v === panoUrl ||
        vNoQuery === panoUrlNoQuery ||
        vFileNoQuery === panoFileNoQuery
      ) return roomId;
    }
    return null;
  }

  // -----------------------------
  // HUD + overlay (minimal, keeps existing CSS classes)
  // -----------------------------

  _createHud() {
    const hud = document.createElement('div');
    hud.className = 'p360-hud';

    // Left interiors
    const left = document.createElement('div');
    left.className = 'p360-hud-left';
    const leftTitle = document.createElement('div');
    leftTitle.className = 'p360-hud-left-title';
    leftTitle.textContent = 'Interiors';
    const leftList = document.createElement('div');
    leftList.className = 'p360-hud-left-list';
    left.appendChild(leftTitle);
    left.appendChild(leftList);
    hud.appendChild(left);

    // Right mode buttons
    const right = document.createElement('div');
    right.className = 'p360-hud-right';
    const mkModeBtn = (label, mode, cls) => {
      const b = document.createElement('button');
      b.type = 'button';
      b.className = `p360-btn p360-btn-mode ${cls}`;
      b.textContent = label;
      b.addEventListener('click', () => this._setViewMode(mode));
      return b;
    };
    this._btnMode360 = mkModeBtn('360', '360', 'p360-btn-mode-360');
    this._btnMode3d = mkModeBtn('3D', '3d', 'p360-btn-mode-3d');
    this._btnMode2d = mkModeBtn('2D', '2d', 'p360-btn-mode-2d');
    right.appendChild(this._btnMode360);
    right.appendChild(this._btnMode3d);
    right.appendChild(this._btnMode2d);
    hud.appendChild(right);

    // Top-center floor selector (house projects only)
    const topCenter = document.createElement('div');
    topCenter.className = 'p360-hud-topcenter';
    topCenter.style.display = 'none';

    const floorBtn = document.createElement('button');
    floorBtn.type = 'button';
    floorBtn.className = 'p360-btn-floor-hud';
    topCenter.appendChild(floorBtn);

    const floorMenu = document.createElement('div');
    floorMenu.className = 'p360-floor-hud-menu';
    floorMenu.style.display = 'none';
    topCenter.appendChild(floorMenu);

    let floorMenuOpen = false;
    const closeFloorMenu = () => {
      floorMenuOpen = false;
      floorMenu.style.display = 'none';
      floorBtn.classList.remove('is-open');
    };
    const onDocClickFloor = (e) => {
      if (!topCenter.contains(e.target)) closeFloorMenu();
    };
    document.addEventListener('click', onDocClickFloor);

    floorBtn.addEventListener('click', (e) => {
      e.stopPropagation();
      floorMenuOpen = !floorMenuOpen;
      floorMenu.style.display = floorMenuOpen ? '' : 'none';
      floorBtn.classList.toggle('is-open', floorMenuOpen);
    });

    hud.appendChild(topCenter);
    this._hudTopCenter = topCenter;
    this._hudFloorBtn = floorBtn;
    this._hudFloorMenu = floorMenu;
    this._hudCloseFloorMenu = closeFloorMenu;
    this._hudOnDocClickFloor = onDocClickFloor;

    // Top-right fullscreen
    const topRight = document.createElement('div');
    topRight.className = 'p360-hud-topright';
    const fs = document.createElement('button');
    fs.type = 'button';
    fs.className = 'p360-btn p360-btn-fullscreen';
    fs.title = 'Fullscreen';
    fs.addEventListener('click', () => this._toggleFullscreen());
    topRight.appendChild(fs);
    hud.appendChild(topRight);

    // Bottom pill (zoom + autorotate + VR)
    const bottom = document.createElement('div');
    bottom.className = 'p360-hud-bottom p360-hud-bottom-pill';

    const mkPill = (title, cls, onClick) => {
      const b = document.createElement('button');
      b.type = 'button';
      b.className = `p360-btn p360-btn-pill ${cls}`;
      b.title = title;
      b.addEventListener('click', onClick);
      return b;
    };

    const zoom = mkPill('Zoom', 'p360-btn-zoom', () => this._cycleZoom());
    zoom.textContent = '1×';
    this._btnZoom = zoom;

    const rotate = mkPill('Auto-rotate', 'p360-btn-autorotate', () => this._toggleAutorotate());
    this._btnAutorotate = rotate;

    bottom.appendChild(zoom);
    bottom.appendChild(rotate);
    hud.appendChild(bottom);

    this.container.appendChild(hud);
    this._hudLeftList = leftList;
    this._buildInteriorButtons();

    this._updateHudState = () => {
      this._btnMode360?.classList.toggle('is-active', this._viewMode === '360');
      this._btnMode2d?.classList.toggle('is-active', this._viewMode === '2d');
      this._btnMode3d?.classList.toggle('is-active', this._viewMode === '3d');
      for (const [name, btn] of this._hudInteriorButtons.entries()) {
        btn.classList.toggle('is-active', name === this._interior);
      }
    };

    return hud;
  }

  _buildInteriorButtons() {
    if (!this._hudLeftList) return;
    this._hudLeftList.innerHTML = '';
    this._hudInteriorButtons.clear();
    for (const name of this._interiors || []) {
      const b = document.createElement('button');
      b.type = 'button';
      b.className = 'p360-btn p360-btn-interior';
      b.textContent = name;
      b.addEventListener('click', () => this._setInterior(name));
      this._hudLeftList.appendChild(b);
      this._hudInteriorButtons.set(name, b);
    }
  }

  _buildFloorSelectorState() {
    // Update floorplan widget (bottom-left card)
    if (this.floorplan?.setFloors) {
      this.floorplan.setFloors(this._floors, this._currentFloor);
    }

    // Update HUD top-center floor selector
    if (!this._hudTopCenter) return;
    const floors = this._floors || [];
    const hasFloors = floors.length > 1;
    this._hudTopCenter.style.display = hasFloors ? '' : 'none';
    if (!hasFloors) return;

    // Label: "1 етаж", "2 етаж", …
    const label = this._currentFloor !== null && this._currentFloor !== undefined
      ? `${this._currentFloor + 1} етаж`
      : '—';
    this._hudFloorBtn.textContent = label;

    // Rebuild menu items
    this._hudFloorMenu.innerHTML = '';
    for (const f of floors) {
      const item = document.createElement('button');
      item.type = 'button';
      item.className = 'p360-floor-hud-option' + (f === this._currentFloor ? ' is-active' : '');
      item.textContent = `${f + 1} етаж`;
      item.addEventListener('click', (e) => {
        e.stopPropagation();
        this._hudCloseFloorMenu?.();
        this._setFloor(f);
      });
      this._hudFloorMenu.appendChild(item);
    }
  }

  _createOverlay() {
    const wrap = document.createElement('div');
    wrap.className = 'p360-overlay';
    wrap.style.display = 'none';

    const img = document.createElement('img');
    img.className = 'p360-overlay-img';
    img.alt = 'Overlay';
    wrap.appendChild(img);

    const pager = document.createElement('div');
    pager.className = 'p360-overlay-pager';
    const prev = document.createElement('button');
    prev.className = 'p360-overlay-pager-btn';
    prev.textContent = '‹';
    const next = document.createElement('button');
    next.className = 'p360-overlay-pager-btn';
    next.textContent = '›';
    const count = document.createElement('div');
    count.className = 'p360-overlay-pager-count';
    pager.appendChild(prev);
    pager.appendChild(count);
    pager.appendChild(next);
    wrap.appendChild(pager);

    prev.addEventListener('click', () => this._navOverlay(-1));
    next.addEventListener('click', () => this._navOverlay(1));

    this.container.appendChild(wrap);
    return {
      wrap,
      img,
      count,
      pager,
      setVisible: (v) => { wrap.style.display = v ? '' : 'none'; },
      setLoading: (v) => { wrap.classList.toggle('is-loading', !!v); }
    };
  }

  _applyOverlayMode(mode) {
    const urls = mode === '2d' ? (this._middleCutUrls || []) : (this._topViewUrl ? [this._topViewUrl] : []);
    this._overlayUrls = urls;
    this._overlayIndex = 0;
    this._overlay.setVisible(true);
    this._psvEl.style.display = 'none';
    // Hide pager arrows in 3D (single image) or when ≤1 image
    if (this._overlay.pager) {
      this._overlay.pager.style.display = (mode === '3d' || urls.length <= 1) ? 'none' : '';
    }
    this._renderOverlay();
  }

  _renderOverlay() {
    const u = this._overlayUrls?.[this._overlayIndex] || null;
    if (!u) return;
    this._overlay.img.src = u;
    this._overlay.count.textContent = `${this._overlayIndex + 1}/${this._overlayUrls.length || 1}`;
  }

  _navOverlay(dir) {
    if (!this._overlayUrls?.length) return;
    const n = this._overlayUrls.length;
    this._overlayIndex = (this._overlayIndex + dir + n) % n;
    this._renderOverlay();
  }

  _setViewMode(mode) {
    this._viewMode = mode;
    this.container.classList.remove('p360-mode-360', 'p360-mode-2d', 'p360-mode-3d');
    this.container.classList.add(`p360-mode-${mode}`);
    if (mode === '360') {
      this._overlay.setVisible(false);
      this._psvEl.style.display = '';
    } else {
      this._applyOverlayMode(mode);
    }
    this._updateHudState?.();
  }

  async _setInterior(name) {
    if (!name || name === this._interior) return;
    // Remember current camera position index (via floorplan_data path map)
    // before rebuilding panoramas for the new interior.
    const pathIdx = this._getCurrentPanoramaPathIndex();

    this._interior = name;
    this._panoramas = this._buildPanoramasForInterior(this._interior);
    this._topViewUrl = this._inferTopViewUrl();
    this._middleCutUrls = await this._inferMiddleCutUrls();
    this._buildInteriorButtons();
    this._updateHudState?.();

    // Try to land on the same camera point in the new interior via path index.
    // Fall back to filename match, then first panorama.
    const byIndex = pathIdx >= 0 ? this._getPanoramaByPathIndex(pathIdx) : null;
    const byFile = !byIndex && this._currentPanoramaId
      ? this._getPanoramaById(this._currentPanoramaId)
      : null;
    const target = byIndex || byFile || this._panoramas[0] || null;
    if (target?.id) await this.loadPanorama(target.id, { reason: 'interior' });
  }

  async _toggleFullscreen() {
    const el = this.container;
    const doc = document;
    const isFs = doc.fullscreenElement === el || doc.webkitFullscreenElement === el;
    if (!isFs) {
      await (el.requestFullscreen?.({ navigationUI: 'hide' }) || el.webkitRequestFullscreen?.());
    } else {
      await (doc.exitFullscreen?.() || doc.webkitExitFullscreen?.());
    }
  }

  _toggleAutorotate() {
    if (!this._psv) return;
    if (typeof this._psv.toggleAutorotate === 'function') {
      this._psv.toggleAutorotate();
    } else if (!this._autorotating && typeof this._psv.startAutorotate === 'function') {
      this._psv.startAutorotate();
    } else if (this._autorotating && typeof this._psv.stopAutorotate === 'function') {
      this._psv.stopAutorotate();
    }
  }

  _cycleZoom() {
    if (!this._psv) return;
    const levels = [0, 50, 100];
    let cur = 0;
    try { cur = this._psv.getZoomLevel?.() ?? 0; } catch {}
    const idx = levels.reduce((best, v, i) => (Math.abs(v - cur) < Math.abs(levels[best] - cur) ? i : best), 0);
    const next = levels[(idx + 1) % levels.length];
    try { this._psv.zoom?.(next); } catch {}
    if (this._btnZoom) this._btnZoom.textContent = next === 0 ? '1×' : (next === 50 ? '1.5×' : '2×');
  }

  /**
   * Returns the floorplan_data path map for the current floor/apartment.
   * House:     floorplan_data.floors["0"] = { "path-0": "Panorama_...webp", ... }
   * Apartment: floorplan_data.floors["apartment"] = { "path-0": "...", ... }
   * Returns null if not present.
   */
  _getFloorplanDataPaths() {
    const fd = this._project?.floorplan_data?.floors;
    if (!fd || typeof fd !== 'object') return null;
    if (this._isHouseProject(this._project) && this._currentFloor !== null) {
      const key = String(this._currentFloor);
      return (fd[key] && typeof fd[key] === 'object') ? fd[key] : null;
    }
    // Apartment: key is "apartment" or first non-numeric key
    const aptKey = Object.keys(fd).find((k) => isNaN(Number(k))) || Object.keys(fd)[0] || null;
    return aptKey ? (fd[aptKey] && typeof fd[aptKey] === 'object' ? fd[aptKey] : null) : null;
  }

  /**
   * Given the current panorama filename, find its path-N index in floorplan_data paths.
   * Returns the index (0-based) or -1 if not found.
   */
  _getCurrentPanoramaPathIndex() {
    const paths = this._getFloorplanDataPaths();
    if (!paths) return -1;
    const curId = this._currentPanoramaId ? String(this._currentPanoramaId) : '';
    const curFile = curId.split('/').pop().split('?')[0].toLowerCase();
    const entries = Object.keys(paths).sort(); // "path-0", "path-1", ...
    for (let i = 0; i < entries.length; i++) {
      const val = String(paths[entries[i]] || '');
      const valFile = val.split('/').pop().split('?')[0].toLowerCase();
      if (valFile && (valFile === curFile || curFile.includes(valFile) || valFile.includes(curFile))) return i;
    }
    return -1;
  }

  /**
   * Given a path index, find the panorama in this._panoramas whose filename
   * matches floorplan_data paths[path-N]. Returns panorama or null.
   */
  _getPanoramaByPathIndex(idx) {
    const paths = this._getFloorplanDataPaths();
    if (!paths || idx < 0) return null;
    const entries = Object.keys(paths).sort();
    const key = entries[idx];
    if (!key) return null;
    const targetFile = String(paths[key] || '').split('/').pop().split('?')[0].toLowerCase();
    if (!targetFile) return null;
    return this._panoramas.find((p) => {
      const f = (p.id || '').split('/').pop().split('?')[0].toLowerCase();
      return f === targetFile || f.includes(targetFile) || targetFile.includes(f);
    }) || null;
  }

  /**
   * Given a floorplan_data path key (e.g. "path-0", "path-1"),
   * find the panorama in this._panoramas whose filename matches.
   * Returns panorama or null.
   */
  _getPanoramaByPathKey(pathKey) {
    const paths = this._getFloorplanDataPaths();
    if (!paths || !pathKey) return null;
    const targetFile = String(paths[pathKey] || '').split('/').pop().split('?')[0].toLowerCase();
    if (!targetFile) return null;
    return this._panoramas.find((p) => {
      const f = (p.id || '').split('/').pop().split('?')[0].toLowerCase();
      return f === targetFile || f.includes(targetFile) || targetFile.includes(f);
    }) || null;
  }

  /**
   * Given the current panorama id, find the floorplan_data path key
   * (e.g. "path-0") that matches it. Returns the key string or null.
   */
  _getCurrentPanoramaPathKey() {
    const paths = this._getFloorplanDataPaths();
    if (!paths) return null;
    const curId = this._currentPanoramaId ? String(this._currentPanoramaId) : '';
    const curFile = curId.split('/').pop().split('?')[0].toLowerCase();
    for (const key of Object.keys(paths)) {
      const val = String(paths[key] || '').split('/').pop().split('?')[0].toLowerCase();
      if (val && (val === curFile || curFile.includes(val) || val.includes(curFile))) return key;
    }
    return null;
  }

  async _onFloorplanNavigate(panoramaId) {
    // If navigating to the generic "first panorama" (from image click with no SVG),
    // try to use floorplan_data path-0 to land on the correct camera point.
    const byPath0 = this._getPanoramaByPathIndex(0);
    const target = byPath0 || this._getPanoramaById(panoramaId);
    if (!target?.id) return;
    await this.analytics.track('floorplan_click', { panoramaId: target.id });
    await this.loadPanorama(target.id, { reason: 'floorplan' });
  }

  async _onFloorplanRoomClick(roomId) {
    const info =
      typeof roomId === 'string'
        ? { roomId, roomName: null, panoramaId: null }
        : (roomId || { roomId: null, roomName: null, panoramaId: null });
    const rid = info?.roomId || null;

    // 1. SVG data-panorama-id attribute (most explicit — set by authoring tool).
    if (info?.panoramaId) {
      const panoByAttr = this._getPanoramaById(info.panoramaId);
      if (panoByAttr?.id) {
        await this.loadPanorama(panoByAttr.id, { reason: 'floorplan_room' });
        return;
      }
    }

    if (!rid) return;

    // 2. Resolve via floorplan_data path key (e.g. "path-0", "path-1").
    // The SVG data-room attributes match these keys.
    const panoByPath = this._getPanoramaByPathKey(rid);
    if (panoByPath?.id) {
      await this.loadPanorama(panoByPath.id, { reason: 'floorplan_room' });
      return;
    }

    // 3. Fallback: legacy room_map / room_id matching
    const map = this._project?.floorplan_data?.room_map || null;
    const mappedId = map && typeof map === 'object' ? map[rid] : null;
    const pano = mappedId ? this._getPanoramaById(mappedId) : (this._panoramas.find((p) => p.room_id === rid) || null);
    if (pano?.id) await this.loadPanorama(pano.id, { reason: 'floorplan_room' });
  }

  _onFloorplanRoomHover(room) {
    void room;
  }

  _inferTopViewUrl() {
    const interior = this._interior;
    // Only show 3D top-view for the currently selected interior
    const candidates = [
      ...this._getProjectImages('3d', interior),
      ...this._getProjectImages('2d', interior)
    ];
    for (const a of candidates) {
      const name = this._getAssetName(a) || '';
      const url = this._getAssetUrl(a);
      if (!url) continue;
      if (name.startsWith('TopView_') || name.includes('TopView_')) return url;
    }
    return null;
  }

  async _inferMiddleCutUrls() {
    const interior = this._interior;
    // Only show 2D images for the currently selected interior
    const candidates = this._getProjectImages('2d', interior);
    const assetUrls = candidates
      .map((a) => {
        const name = this._getAssetName(a) || '';
        const url = this._getAssetUrl(a);
        if (!url) return null;
        if (!/\.(webp|jpe?g|png)$/i.test(name.split('?')[0] || name)) return null;
        return { name, url };
      })
      .filter(Boolean)
      .sort((a, b) => String(a.name).localeCompare(String(b.name)))
      .map((x) => x.url);
    return assetUrls;
  }
}

