/**
 * Floorplan
 *
 * HTML overlay that renders:
 * - a PNG floorplan image (background)
 * - an optional SVG overlay for room click/selection/highlighting
 * - optional panorama point dots (fallback / legacy)
 * Keeps DOM responsibilities out of Three.js modules.
 */

// (no Utils imports needed here anymore)

export class Floorplan {
  /**
   * @param {object} opts
   * @param {HTMLElement} opts.root
   * @param {(panoramaId: string) => void} opts.onNavigatePanorama
   * @param {(room: (string|{roomId:string, roomName?:string|null, panoramaId?:string|null})) => void} [opts.onRoomClick]
   * @param {(room: {roomId:string, roomName?:string|null, panoramaId?:string|null}) => void} [opts.onRoomHover]
   */
  constructor({ root, onNavigatePanorama, onRoomClick, onRoomHover, onFloorSelect }) {
    this.root = root;
    this.onNavigatePanorama = onNavigatePanorama;
    this.onRoomClick = onRoomClick || null;
    this.onRoomHover = onRoomHover || null;
    this.onFloorSelect = onFloorSelect || null;

    this.el = document.createElement('div');
    this.el.className = 'p360-floorplan';
    this.el.setAttribute('aria-label', 'Floorplan');

    // Floor selector (top-center label, visible only for house type projects)
    // The label button lives inside the floorplan card; the dropdown is appended
    // to the root so it can overflow the clipped card.
    this._floorSelectorEl = document.createElement('div');
    this._floorSelectorEl.className = 'p360-floor-selector';
    this._floorSelectorEl.style.display = 'none';

    this._floorLabelBtn = document.createElement('button');
    this._floorLabelBtn.type = 'button';
    this._floorLabelBtn.className = 'p360-floor-label-btn';
    this._floorSelectorEl.appendChild(this._floorLabelBtn);

    this._floorDropdown = document.createElement('div');
    this._floorDropdown.className = 'p360-floor-dropdown';
    this._floorDropdown.style.display = 'none';
    // Dropdown is appended to root so it is not clipped by the floorplan card.
    // Its position is computed in JS when opened.

    this._floorSelectorOpen = false;
    this._floorLabelBtn.addEventListener('click', (e) => {
      e.stopPropagation();
      this._toggleFloorDropdown();
    });

    // Close dropdown on outside click
    this._onDocClick = (e) => {
      if (!this._floorSelectorEl.contains(e.target) && !this._floorDropdown.contains(e.target)) {
        this._closeFloorDropdown();
      }
    };
    document.addEventListener('click', this._onDocClick);

    this.el.appendChild(this._floorSelectorEl);

    this.img = document.createElement('img');
    this.img.alt = 'Floorplan';
    this.el.appendChild(this.img);

    this.svgLayer = document.createElement('div');
    this.svgLayer.className = 'p360-floorplan-svg';
    this.el.appendChild(this.svgLayer);

    // Backdrop sits behind the expanded floorplan (but below HUD), to match the
    // "modal card" feel and prevent accidental camera drags while open.
    this.backdrop = document.createElement('div');
    this.backdrop.className = 'p360-floorplan-backdrop';
    // Keep in DOM so opacity transitions can run; CSS controls pointer-events.
    this.root.appendChild(this.backdrop);

    // Mobile UX: tap floorplan to expand centered/bigger; tap X or Esc to close.
    this._expanded = false;
    this._closeBtn = document.createElement('button');
    this._closeBtn.type = 'button';
    this._closeBtn.className = 'p360-floorplan-close';
    this._closeBtn.setAttribute('aria-label', 'Close floorplan');
    this._closeBtn.title = 'Close';
    this._closeBtn.textContent = '×';
    this.el.appendChild(this._closeBtn);

    this._isMobileLayout = () => {
      try {
        return window.matchMedia && window.matchMedia('(max-width: 520px)').matches;
      } catch {
        return false;
      }
    };

    this._setExpanded = (next) => {
      const want = !!next;
      // Only enable this UX in the small/mobile layout.
      if (want && !this._isMobileLayout()) return;
      this._expanded = want;
      this.el.classList.toggle('is-expanded', want);
      this.backdrop.classList.toggle('is-visible', want);
    };

    this._onFloorplanClickCapture = (e) => {
      // If already expanded, preserve normal room click behavior.
      if (this._expanded) return;
      if (!this._isMobileLayout()) return;
      // First tap expands; it should not trigger room navigation in the SVG on that same tap.
      e.preventDefault();
      e.stopPropagation();
      this._setExpanded(true);
    };

    this._onCloseClick = (e) => {
      e.preventDefault();
      e.stopPropagation();
      this._setExpanded(false);
    };

    this._onBackdropClick = (e) => {
      e.preventDefault();
      e.stopPropagation();
      this._setExpanded(false);
    };

    this._onKeyDown = (e) => {
      if (!this._expanded) return;
      if (e.key === 'Escape') this._setExpanded(false);
    };

    this._onResize = () => {
      // If the viewport grows, auto-collapse.
      if (this._expanded && !this._isMobileLayout()) this._setExpanded(false);
    };

    // Capture to run before SVG's bubbling click handlers.
    this.el.addEventListener('click', this._onFloorplanClickCapture, { capture: true });
    this._closeBtn.addEventListener('click', this._onCloseClick);
    this.backdrop.addEventListener('click', this._onBackdropClick);
    window.addEventListener('keydown', this._onKeyDown);
    window.addEventListener('resize', this._onResize, { passive: true });

    // SVG room click/hover — delegated from this.el so pointer-events on the SVG
    // root can be "none" (only room shapes with pointer-events="all" receive events).
    this.el.addEventListener('click', (e) => {
      const svg = this._svgDocEl;
      if (!svg) return;
      const target = e.target;
      if (!(target instanceof Element)) return;
      // Only handle clicks that originated inside the SVG.
      if (!svg.contains(target)) return;
      const info = this._getRoomInfoFromTarget(target, svg);
      if (!info) return;
      e.stopPropagation();
      this.onRoomClick?.(info);
      const coords = this._getFloorplanCoordsFromEvent(e);
      this.el.dispatchEvent(new CustomEvent('p360:floorplanRoomClick', {
        detail: { roomId: info.roomId, roomName: info.roomName || null, panoramaId: info.panoramaId || null, status: info.status || null, x: coords?.x ?? null, y: coords?.y ?? null },
        bubbles: false
      }));
    });

    this.el.addEventListener('pointermove', (e) => {
      const svg = this._svgDocEl;
      if (!svg) return;
      const target = e.target;
      if (!(target instanceof Element)) return;
      if (!svg.contains(target)) { this._clearHoverRoom(); return; }
      const info = this._getRoomInfoFromTarget(target, svg);
      if (!info) { this._clearHoverRoom(); return; }
      this._setHoverRoom(info);
    });

    this.el.addEventListener('pointerleave', () => this._clearHoverRoom());

    this.root.appendChild(this.el);
    this.root.appendChild(this._floorDropdown);

    this._activeId = null;
    this._activeRoomId = null;
    this._svgDocEl = null;
    this._svgRect = null; // { left, top, width, height } within container
    this._svgNeedsViewBox = false;
    this._hoverRoomEl = null;
    this._hoverRoomId = null;
    this._roomMeta = new Map(); // roomId -> { name?, status?, panoramaId? }

    this._resizeObserver = new ResizeObserver(() => {
      // Keep SVG aligned to PNG when the widget is resized.
      this._syncSvgToImage();
    });
    this._resizeObserver.observe(this.el);
  }

  setOpen(open) {
    // Floorplan is always visible now; keep this method as a no-op for
    // backwards-compatibility with integrations calling it.
    void open;
    this.el.classList.remove('is-open');
  }

  toggle() {
    // No-op: floorplan stays visible (removes open/close behavior).
    this.setOpen(true);
  }

  /**
   * @param {object|null} floorplan row
   * @param {Array<object>} panoramas rows
   */
  async setData(floorplan, panoramas) {
    this.svgLayer.innerHTML = '';
    this._svgDocEl = null;
    this._hoverRoomEl = null;
    this._hoverRoomId = null;
    this._panoramas = panoramas || [];

    if (!floorplan?.image_url && !floorplan?.svg_url) {
      this.img.removeAttribute('src');
      this.img.style.cursor = '';
      return;
    }

    if (floorplan.image_url) {
      this.img.src = floorplan.image_url;
    }
    await this._getImageNaturalSize(this.img);

    // Make image clickable to navigate to first panorama when there's no SVG overlay
    if (!floorplan.svg_url && this._panoramas.length > 0) {
      this.img.style.cursor = 'pointer';
      this.img.onclick = () => {
        const first = this._panoramas[0];
        if (first?.id) this.onNavigatePanorama?.(first.id);
      };
    } else {
      this.img.style.cursor = '';
      this.img.onclick = null;
    }

    // Optional SVG overlay (for room highlighting and room click navigation).
    if (floorplan.svg_url) {
      await this._loadSvgOverlay(floorplan.svg_url);
      this._applyRoomMetaToSvg();
      this._applyActiveRoomToSvg();
    }

    // Align SVG to the exact rendered PNG rectangle (matches object-fit: contain).
    this._syncSvgToImage();
  }

  /**
   * Highlight an SVG room by id.
   * We support multiple authoring styles:
   * - element with id="ROOM_ID"
   * - element with data-room="ROOM_ID"
   */
  setActiveRoom(roomId) {
    this._activeRoomId = roomId || null;
    this._applyActiveRoomToSvg();
  }

  /**
   * Set room metadata loaded from DB.
   * @param {Record<string, {name?:string|null,status?:string|null,panoramaId?:string|null}>|Array<{roomId:string,name?:string,status?:string,panoramaId?:string}>|null} meta
   */
  setRoomMeta(meta) {
    this._roomMeta.clear();
    if (Array.isArray(meta)) {
      for (const r of meta) {
        if (!r?.roomId) continue;
        this._roomMeta.set(String(r.roomId), {
          name: r?.name ?? null,
          status: r?.status ?? null,
          panoramaId: r?.panoramaId ?? null
        });
      }
    } else if (meta && typeof meta === 'object') {
      for (const [roomId, v] of Object.entries(meta)) {
        if (!roomId) continue;
        this._roomMeta.set(String(roomId), {
          name: v?.name ?? null,
          status: v?.status ?? null,
          panoramaId: v?.panoramaId ?? null
        });
      }
    }
    this._applyRoomMetaToSvg();
  }

  async _loadSvgOverlay(svgUrl) {
    try {
      const res = await fetch(svgUrl, { method: 'GET' });
      let text = await res.text();

      // Some authoring/export pipelines omit the SVG namespace (xmlns) or include JSX-ish
      // attributes like `className`. Missing `xmlns` can cause DOMParser to return <parsererror>.
      // We normalize the opening <svg ...> tag to include the standard SVG namespace.
      if (/<svg[\s>]/i.test(text) && !/<svg[^>]*\sxmlns\s*=/i.test(text)) {
        text = text.replace(/<svg(\s[^>]*)?>/i, (m, attrs = '') => `<svg${attrs || ''} xmlns="http://www.w3.org/2000/svg">`);
      }

      const parser = new DOMParser();
      let doc = parser.parseFromString(text, 'image/svg+xml');
      let svg = doc.documentElement;

      // Fallback: if we got a parsererror, try parsing as HTML and extract the <svg>.
      if (svg && svg.nodeName && svg.nodeName.toLowerCase() === 'parsererror') {
        doc = parser.parseFromString(text, 'text/html');
        svg = doc.querySelector('svg');
      }

      if (!svg || svg.nodeName.toLowerCase() !== 'svg') return;

      // Remove any script tags (defensive).
      svg.querySelectorAll('script').forEach((n) => n.remove());

      // Strip <style> blocks inside the SVG that may conflict with our CSS overlay.
      svg.querySelectorAll('style').forEach((n) => n.remove());

      // Make the SVG a transparent click overlay:
      // - All elements: remove visible color attributes, set fill="transparent" so SVG
      //   hit-testing still works (unlike fill="none", "transparent" IS hit-testable).
      // - Elements with data-room / data-room-id: set pointer-events="all" as attribute
      //   so clicks register regardless of computed style.
      svg.querySelectorAll('*').forEach((el) => {
        el.removeAttribute('stroke');
        el.removeAttribute('stroke-width');
        el.removeAttribute('opacity');
        el.removeAttribute('fill-opacity');
        el.removeAttribute('stroke-opacity');
        if (el.style) {
          el.style.removeProperty('stroke');
          el.style.removeProperty('stroke-width');
          el.style.removeProperty('opacity');
          el.style.removeProperty('fill-opacity');
          el.style.removeProperty('stroke-opacity');
          el.style.removeProperty('fill');
        }
        // Set fill to transparent (hit-testable) instead of removing it.
        // CSS will override this for hover/active states via !important.
        el.setAttribute('fill', 'transparent');
      });

      // Ensure room elements and their children are always pointer-targetable.
      svg.querySelectorAll('[data-room], [data-room-id]').forEach((el) => {
        el.setAttribute('pointer-events', 'all');
        el.querySelectorAll('*').forEach((child) => child.setAttribute('pointer-events', 'all'));
      });

      // Ensure the SVG scales to container.
      svg.setAttribute('preserveAspectRatio', 'xMidYMid meet');
      svg.style.width = '100%';
      svg.style.height = '100%';
      svg.style.display = 'block';
      svg.style.position = 'absolute';
      svg.style.pointerEvents = 'none';

      // Store reference so the el-level listener can find the current svg.
      // (Click and hover are delegated from this.el to avoid pointer-events conflicts.)

      this.svgLayer.appendChild(svg);
      this._svgDocEl = svg;
      this.svgLayer.style.pointerEvents = 'none';

      // If the SVG lacks a viewBox, we'll set it later once we know the image's natural size.
      // That guarantees SVG and PNG share the same coordinate system.
      this._svgNeedsViewBox = !svg.getAttribute('viewBox');
    } catch {
      // Ignore SVG overlay failures; PNG + points still works.
    }
  }

  _getRoomInfoFromTarget(target, svgRoot) {
    // Support authoring where the clickable id/data-room is on a parent <g>,
    // but the actual hover/click hits a child <path>.
    const hit = target.closest?.('[data-room], [data-room-id]') || target;
    if (!(hit instanceof Element)) return null;
    if (hit === svgRoot) return null;

    // Support both authoring styles:
    // - data-room="kitchen"
    // - data-room-id="room-1"
    const explicitRoomId =
      hit.getAttribute('data-room') ||
      hit.getAttribute('data-room-id') ||
      null;
    if (!explicitRoomId) return null;

    const panoramaId =
      hit.getAttribute('data-panorama-id') ||
      hit.getAttribute('data-panorama') ||
      null;
    // Status should come from DB-driven metadata (applied as data-status).
    // Do NOT infer it from SVG classes, since the SVG export may contain arbitrary classes.
    const status = hit.getAttribute('data-status') || null;

    // Room name conventions (best-effort):
    // - data-room-name="Kitchen"
    // - data-name="Kitchen"
    // - aria-label="Kitchen"
    // - <title>Kitchen</title> inside the element
    const titleNode = hit.querySelector?.('title') || null;
    const roomName =
      hit.getAttribute('data-room-name') ||
      hit.getAttribute('data-name') ||
      hit.getAttribute('aria-label') ||
      (titleNode?.textContent ? titleNode.textContent.trim() : null) ||
      null;

    return { roomId: explicitRoomId, roomName, panoramaId, status, el: hit };
  }

  _setHoverRoom(info) {
    const { roomId, roomName, panoramaId, status, el } = info;
    if (this._hoverRoomEl && this._hoverRoomEl !== el) {
      this._hoverRoomEl.classList.remove('is-hover-room');
    }
    this._hoverRoomEl = el;
    this._hoverRoomId = roomId;
    el.classList.add('is-hover-room');

    // Emit hover callback (editor integrations).
    this.onRoomHover?.({ roomId, roomName, panoramaId, status });

    // Dispatch a DOM event so host apps can hook without wiring callbacks.
    this.el.dispatchEvent(new CustomEvent('p360:floorplanRoomHover', {
      detail: { roomId, roomName, panoramaId, status },
      bubbles: true
    }));
  }

  _applyRoomMetaToSvg() {
    const svg = this._svgDocEl;
    if (!svg) return;
    for (const el of svg.querySelectorAll('[data-room], [data-room-id]')) {
      const rid = el.getAttribute('data-room') || el.getAttribute('data-room-id') || '';
      if (!rid) continue;
      const meta = this._roomMeta.get(rid) || null;
      if (!meta) continue;
      if (meta.name && !el.getAttribute('data-room-name')) el.setAttribute('data-room-name', String(meta.name));
      if (meta.status) el.setAttribute('data-status', String(meta.status));
      if (meta.panoramaId && !el.getAttribute('data-panorama-id')) el.setAttribute('data-panorama-id', String(meta.panoramaId));
    }
  }

  _getFloorplanCoordsFromEvent(evt) {
    const svg = this._svgDocEl;
    if (!svg) return null;
    const vb = svg.viewBox?.baseVal;
    const vbw = vb?.width || svg.viewBox?.animVal?.width || svg.clientWidth;
    const vbh = vb?.height || svg.viewBox?.animVal?.height || svg.clientHeight;
    if (!(vbw > 0 && vbh > 0)) return null;
    const r = svg.getBoundingClientRect();
    const px = (evt.clientX - r.left) / Math.max(1, r.width);
    const py = (evt.clientY - r.top) / Math.max(1, r.height);
    return { x: Math.round(px * vbw), y: Math.round(py * vbh) };
  }

  _clearHoverRoom() {
    if (this._hoverRoomEl) this._hoverRoomEl.classList.remove('is-hover-room');
    this._hoverRoomEl = null;
    this._hoverRoomId = null;
  }


  _syncSvgToImage() {
    const svg = this._svgDocEl;
    if (!svg) return;
    const img = this.img;
    if (!img) return;

    // Need intrinsic image size to compute object-fit: contain rect.
    const iw = img.naturalWidth;
    const ih = img.naturalHeight;

    // If no PNG (SVG-only floorplan), fill the container entirely.
    if (!(iw > 0 && ih > 0)) {
      const rect = this.el.getBoundingClientRect();
      const cw = rect.width;
      const ch = rect.height;
      if (!(cw > 0 && ch > 0)) return;
      svg.style.left = '0px';
      svg.style.top = '0px';
      svg.style.width = `${cw}px`;
      svg.style.height = `${ch}px`;
      svg.style.transformOrigin = '0 0';
      return;
    }

    // Ensure the SVG has a viewBox matching the raster floorplan size.
    // This makes it much easier for authors to export SVG overlays that click-align.
    if (this._svgNeedsViewBox && !svg.getAttribute('viewBox')) {
      svg.setAttribute('viewBox', `0 0 ${iw} ${ih}`);
      this._svgNeedsViewBox = false;
    }

    const rect = this.el.getBoundingClientRect();
    const cw = rect.width;
    const ch = rect.height;
    if (!(cw > 0 && ch > 0)) return;

    const scale = Math.min(cw / iw, ch / ih);
    const snap = (v) => {
      const dpr = window.devicePixelRatio || 1;
      return Math.round(v * dpr) / dpr;
    };

    const rw = snap(iw * scale);
    const rh = snap(ih * scale);
    const left = snap((cw - rw) / 2);
    const top = snap((ch - rh) / 2);

    // Store for potential future mapping needs.
    this._svgRect = { left, top, width: rw, height: rh };

    svg.style.left = `${left}px`;
    svg.style.top = `${top}px`;
    svg.style.width = `${rw}px`;
    svg.style.height = `${rh}px`;
    svg.style.transformOrigin = '0 0';
  }

  async _getImageNaturalSize(imgEl) {
    try {
      // Already loaded
      if (imgEl?.complete && imgEl.naturalWidth > 0 && imgEl.naturalHeight > 0) {
        return { width: imgEl.naturalWidth, height: imgEl.naturalHeight };
      }
      // Wait for load/error (best-effort; don't block forever).
      await new Promise((resolve) => {
        let settled = false;
        const done = () => {
          if (settled) return;
          settled = true;
          imgEl.removeEventListener('load', done);
          imgEl.removeEventListener('error', done);
          resolve();
        };
        imgEl.addEventListener('load', done, { once: true });
        imgEl.addEventListener('error', done, { once: true });
        setTimeout(done, 2500);
      });
      if (imgEl.naturalWidth > 0 && imgEl.naturalHeight > 0) {
        return { width: imgEl.naturalWidth, height: imgEl.naturalHeight };
      }
      return null;
    } catch {
      return null;
    }
  }

  _applyActiveRoomToSvg() {
    const svg = this._svgDocEl;
    if (!svg) return;
    const roomId = this._activeRoomId;

    // Clear previous highlights
    svg.querySelectorAll('[data-room].is-active-room, [data-room-id].is-active-room, .is-active-room').forEach((el) => {
      el.classList.remove('is-active-room');
    });

    if (!roomId) return;
    const el =
      svg.querySelector(`[data-room="${CSS.escape(roomId)}"]`) ||
      svg.querySelector(`[data-room-id="${CSS.escape(roomId)}"]`) ||
      null;
    if (el) el.classList.add('is-active-room');
  }

  /**
   * Set available floors and currently selected floor (for house-type projects).
   * @param {number[]} floors - sorted array of floor numbers
   * @param {number|null} currentFloor - currently active floor number
   */
  setFloors(floors, currentFloor) {
    if (!floors || floors.length === 0) {
      this._floorSelectorEl.style.display = 'none';
      return;
    }
    this._floorSelectorEl.style.display = '';
    this._renderFloorLabel(currentFloor);
    this._renderFloorDropdown(floors, currentFloor);
  }

  _renderFloorLabel(currentFloor) {
    const label = currentFloor !== null && currentFloor !== undefined
      ? `${currentFloor + 1} етаж`
      : '—';
    this._floorLabelBtn.textContent = label;
  }

  _renderFloorDropdown(floors, currentFloor) {
    this._floorDropdown.innerHTML = '';
    for (const f of floors) {
      const btn = document.createElement('button');
      btn.type = 'button';
      btn.className = 'p360-floor-option' + (f === currentFloor ? ' is-active' : '');
      btn.textContent = `${f + 1} етаж`;
      btn.addEventListener('click', (e) => {
        e.stopPropagation();
        this._closeFloorDropdown();
        this.onFloorSelect?.(f);
      });
      this._floorDropdown.appendChild(btn);
    }
  }

  _toggleFloorDropdown() {
    this._floorSelectorOpen = !this._floorSelectorOpen;
    this._floorLabelBtn.classList.toggle('is-open', this._floorSelectorOpen);
    if (this._floorSelectorOpen) {
      // Position dropdown above the label button, anchored to root container.
      const btnRect = this._floorLabelBtn.getBoundingClientRect();
      const rootRect = this.root.getBoundingClientRect();
      this._floorDropdown.style.display = '';
      // Let it render first to get its dimensions
      requestAnimationFrame(() => {
        const ddRect = this._floorDropdown.getBoundingClientRect();
        const ddW = ddRect.width || 80;
        const ddH = ddRect.height || 0;
        const btnCenterX = btnRect.left + btnRect.width / 2 - rootRect.left;
        const btnTop = btnRect.top - rootRect.top;
        this._floorDropdown.style.left = `${Math.max(4, btnCenterX - ddW / 2)}px`;
        this._floorDropdown.style.top = `${Math.max(4, btnTop - ddH - 4)}px`;
      });
    } else {
      this._floorDropdown.style.display = 'none';
    }
  }

  _closeFloorDropdown() {
    this._floorSelectorOpen = false;
    this._floorDropdown.style.display = 'none';
    this._floorLabelBtn.classList.remove('is-open');
  }

  destroy() {
    if (this.el?.parentNode) this.el.parentNode.removeChild(this.el);
    if (this.backdrop?.parentNode) this.backdrop.parentNode.removeChild(this.backdrop);
    if (this._floorDropdown?.parentNode) this._floorDropdown.parentNode.removeChild(this._floorDropdown);
    this._resizeObserver?.disconnect?.();
    try { this.el?.removeEventListener?.('click', this._onFloorplanClickCapture, { capture: true }); } catch {}
    try { this._closeBtn?.removeEventListener?.('click', this._onCloseClick); } catch {}
    try { this.backdrop?.removeEventListener?.('click', this._onBackdropClick); } catch {}
    document.removeEventListener('click', this._onDocClick);
    window.removeEventListener('keydown', this._onKeyDown);
    window.removeEventListener('resize', this._onResize);
  }
}


